'use strict';

var coreContext = require('@nordic/core-context');

// TODO: Remove this file when andes migrates to core getters
function getDeviceInfo() {
    return {
        type: coreContext.getDeviceType(),
        context: coreContext.getPlatformType(),
        webView: !!coreContext.getWebviewInfo(),
    };
}

exports.getDeviceInfo = getDeviceInfo;
